package com.example.secondphone.controller;
import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import com.example.secondphone.dto.*;import com.example.secondphone.service.AuthService;import jakarta.validation.Valid;
@RestController @RequestMapping("/api/auth") public class AuthController{private final AuthService auth;public AuthController(AuthService auth){this.auth=auth;}@PostMapping("/register")ResponseEntity<MemberResponse> register(@Valid @RequestBody RegisterRequest request){return ResponseEntity.status(HttpStatus.CREATED).body(auth.register(request));}@PostMapping("/login")AuthResponse login(@Valid @RequestBody LoginRequest request){return auth.login(request);}@GetMapping("/me")MemberResponse me(Authentication authentication){return MemberResponse.from(auth.current(authentication.getName()));}}
